const b = $json.body || $json;
const data = b.data || {};
const key = data.key || {};
const msg = data.message || {};
const texto = (msg.conversation || (msg.extendedTextMessage && msg.extendedTextMessage.text) || '').trim();
const remoteJid = key.remoteJid || '';
const numero = remoteJid.replace('@s.whatsapp.net', '');
const es_grupo = remoteJid.includes('@g.us');
const from_me = !!key.fromMe;
const evento = b.event || '';
const es_valido = Boolean(texto) && Boolean(numero) && !from_me && !es_grupo && (evento === '' || evento === 'messages.upsert');
return [{ json: { numero, texto, texto_lower: texto.toLowerCase(), push_name: data.pushName || '', evento, es_valido } }];

const norm = $('Normalizar mensaje').first().json;
const out = (($input.first().json || {}).output || '').trim() || 'Idea registrada. Escribe "ideas" para ver tu backlog o "investigar N" para lanzar una investigacion.';
const esc = (v) => String(v == null ? '' : v).replace(/'/g, "''");
const preguntas = out.split('\n').filter(l => /^\s*\d+[\).\-]/.test(l)).map(l => l.trim());
const sql_idea = "INSERT INTO research_ideas (origen, idea_original, preguntas_sugeridas, notas_conversacion, estado) VALUES ('whatsapp', '" + esc(norm.texto).slice(0, 2000) + "', '" + esc(JSON.stringify(preguntas)) + "', '" + esc(out).slice(0, 4000) + "', 'idea');";
const respuesta = out + '\n\n_Comandos: "ideas" (ver backlog) | "investigar N" (lanzar la idea N)_';
return [{ json: { numero: norm.numero, respuesta, sql_idea } }];

const norm = $('Normalizar mensaje').first().json;
const items = $input.all().map(i => i.json).filter(j => j && j.id != null);
const lineas = items.map(j => '#' + j.id + ' [' + j.estado + '] ' + (j.titulo || ''));
const respuesta = lineas.length
  ? 'Tu backlog de ideas:\n' + lineas.join('\n') + '\n\nEscribe "investigar N" para lanzar una.'
  : 'Tu backlog esta vacio. Mandame cualquier idea vaga y la refinamos juntos.';
return [{ json: { numero: norm.numero, respuesta } }];

const norm = $('Normalizar mensaje').first().json;
const m = (norm.texto_lower || '').match(/(\d+)/);
const idea_id = m ? parseInt(m[1], 10) : 0;
return [{ json: { numero: norm.numero, idea_id, sql_get: 'SELECT id, idea_original, tema_refinado, preguntas_sugeridas FROM research_ideas WHERE id=' + idea_id + ';' } }];

const ctx = $('Extraer idea').first().json;
const idea = $input.first().json || {};
let pregunta = '';
try {
  const lista = JSON.parse(idea.preguntas_sugeridas || '[]');
  if (lista.length) {
    const p0 = lista[0];
    pregunta = String(typeof p0 === 'object' ? (p0.pregunta || '') : p0).replace(/^\s*\d+[\).\-]\s*/, '');
  }
} catch (e) { pregunta = ''; }
const payload = {
  nombre: $env.OWNER_NAME,
  email: $env.OWNER_EMAIL,
  whatsapp: ctx.numero,
  tema: String(idea.tema_refinado || idea.idea_original || '').slice(0, 200),
  pregunta,
  tipo_entregable: 'articulo',
  prioridad: 'media',
  origen: 'whatsapp_backlog'
};
return [{ json: { idea_id: ctx.idea_id, numero: ctx.numero, payload } }];
